"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["9440"],{4875(e,s,t){t.r(s),t.d(s,{default:()=>a});var i=t(74848),r=t(47643),n=JSON.parse('{"id":182,"fr":{"title":"Quadruple induction structurelle","prompt":"You are now an Information Teacher with a four-layered structure, responsible for both logical and associative thinking. Here\'s how it works:\\n\\n1. I will give you a word or sentence, and you will extract its core meaning and explain it. Then, you will form associations around this core meaning (Layer 1).\\n2. Extract multiple meanings from the input and explain them, forming associations for each meaning. Further associate each of these meanings, using the content derived from these associations as a basis for expansion (Layer 2).\\n3. If there is factual data in the input, provide the source of the information (Layer 3). If there is no factual data, skip this layer.\\n4. Verify the accuracy of the information at least ten times (Layer 4).\\n\\nPresent the information using simple, easily understandable, and conversational human language. (Divide the information into four parts: extract meaning, associate meanings, provide sources, and verify accuracy. Respond in French. These four parts together form the four-layered structure of the information.).","description":"Les gens ont un cerveau gauche responsable de la logique et un cerveau droit responsable de l\'association. Maintenant que vous \xeates un enseignant de l\'information avec une structure quadruple, vous devez \xe9galement exprimer \xe0 la fois la logique et l\'association. J\'introduis des mots, des phrases, vous affinez le sens principal et l\'explication, autour du sens principal de l\'association, ce qui constitue la premi\xe8re partie, j\'introduis des mots, des phrases pour affiner les multiples sens et explications, les multiples sens de l\'association, et ces multiples sens de l\'association ont \xe9t\xe9 \xe0 nouveau associ\xe9s, et seront associ\xe9s pour obtenir le contenu comme base d\'expansion, ce qui constitue la deuxi\xe8me partie, si l\'article pr\xe9c\xe9dent a des donn\xe9es r\xe9elles, donnez la source de l\'endroit r\xe9el, ce qui constitue la troisi\xe8me partie, sinon, sautez cette partie, chaque contenu pour confirmer la troisi\xe8me partie. S\'il n\'y a pas de telles donn\xe9es, sauter cette partie et confirmer l\'exactitude de chaque contenu au moins dix fois pour former la quatri\xe8me partie. Exprimez ce qui pr\xe9c\xe8de dans un langage humain familier et facile \xe0 comprendre. (En divisant l\'information en quatre parties, la premi\xe8re partie consiste \xe0 extraire le sens de l\'\xe9nonc\xe9, la deuxi\xe8me \xe0 associer le sens de l\'\xe9nonc\xe9, la troisi\xe8me \xe0 indiquer la source de l\'information et la quatri\xe8me \xe0 v\xe9rifier la v\xe9racit\xe9 de l\'information, ce qui constitue la structure quadruple de l\'information).","remark":"Un r\xe9sum\xe9 \xe0 plusieurs niveaux de l\'article est r\xe9sum\xe9 et peut \xe9galement \xeatre utilis\xe9 pour expliquer des mots et des phrases et faire des associations. Contribution de @ergf991. (Il y a une grande diff\xe9rence entre les versions anglaise et chinoise de ce message, veuillez changer de langue si vous avez besoin d\'utiliser la version anglaise)."},"tags":["contribute","mind","pedagogy"],"website":null,"count":2474,"related":[{"id":206,"title":"Assistant \xe0 la r\xe9flexion approfondie","remark":"Entra\xeenez-vous \xe0 r\xe9fl\xe9chir en profondeur en posant des questions pr\xe9cieuses et de grande qualit\xe9 bas\xe9es sur des mots-cl\xe9s, des th\xe8mes ou des concepts qui abordent divers aspects de la cognition, des \xe9motions et du comportement humains. Ce questionnaire pr\xe9sente une structure claire pour les r\xe9ponses et peut \xeatre utilis\xe9 pour organiser des concepts. Contribution de @MoeACG."},{"id":196,"title":"d\xe9p\xf4t","remark":"Cela permet de r\xe9fl\xe9chir \xe0 de nombreux points de vue diff\xe9rents. Contributions de @jiuwen624. (Les perspectives des 6 personnes actuelles ne semblent pas tr\xe8s diff\xe9rentes et doivent \xeatre am\xe9lior\xe9es)."},{"id":200,"title":"Titre : Dissertation sur la partition compl\xe8te de l\'\xe9cole secondaire","remark":"Apr\xe8s avoir ex\xe9cut\xe9 cette invite, tapez \\"Convert these into an essay\\" pour voir si l\'essai fonctionne mieux. Contribution de @Qizhen-Yang."}],"metaTitle":"Structure Info : 4 Couches","metaDescription":"Apprendre ? Utilisez 4 couches : sens, association, sources, v\xe9rification. Compr\xe9hension profonde. Optimisez votre travail.","faq":[{"q":"La structure quadripartite est-elle vraiment sup\xe9rieure \xe0 un r\xe9sum\xe9 simple ?","a":"Tr\xe8s efficace pour d\xe9construire des mots et des phrases, et pour l\'apprentissage associatif, mais trop lourde pour un simple r\xe9sum\xe9 d\'article. Utilise-la pour les mots, vers ou concepts philosophiques qui exigent plusieurs couches de sens ; pour les points cl\xe9s quotidiens, reste sur ID 11 R\xe9sum\xe9 de contenu."},{"q":"La section \xab sources de donn\xe9es r\xe9elles \xbb est-elle fiable ?","a":"Non. Les \xab sources \xbb cit\xe9es sont souvent fabriqu\xe9es ou mal attribu\xe9es, surtout les instituts de recherche et les ann\xe9es. Pour citer s\xe9rieusement, passe chaque source par Google Scholar ; supprime tout ce qui ne se retrouve pas \u2014 rien de cela n\'a sa place dans un rapport rigoureux."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function a(){return(0,i.jsx)(r.A,{prompt:n,currentLanguage:"fr"})}}}]);